// Inline CIOS Montgomery multiply
static inline void p2_mul(const uint64_t a[4], const uint64_t b[4], uint64_t r[4]) {
    uint64_t t0=0,t1=0,t2=0,t3=0,t4=0;
    #define P2_ITER(I) do { \
        uint128_t w; uint64_t c; \
        w=(uint128_t)a[I]*b[0]+t0; t0=(uint64_t)w; c=(uint64_t)(w>>64); \
        w=(uint128_t)a[I]*b[1]+t1+c; t1=(uint64_t)w; c=(uint64_t)(w>>64); \
        w=(uint128_t)a[I]*b[2]+t2+c; t2=(uint64_t)w; c=(uint64_t)(w>>64); \
        w=(uint128_t)a[I]*b[3]+t3+c; t3=(uint64_t)w; c=(uint64_t)(w>>64); \
        t4+=c; \
        uint64_t m=t0*P2_FR_INV; \
        w=(uint128_t)m*P2_FR_P[0]+t0; c=(uint64_t)(w>>64); \
        w=(uint128_t)m*P2_FR_P[1]+t1+c; t0=(uint64_t)w; c=(uint64_t)(w>>64); \
        w=(uint128_t)m*P2_FR_P[2]+t2+c; t1=(uint64_t)w; c=(uint64_t)(w>>64); \
        w=(uint128_t)m*P2_FR_P[3]+t3+c; t2=(uint64_t)w; c=(uint64_t)(w>>64); \
        t3=t4+c; t4=0; \
    } while(0)
    P2_ITER(0); P2_ITER(1); P2_ITER(2); P2_ITER(3);
    #undef P2_ITER
    uint64_t borrow=0; uint128_t d;
    uint64_t r0,r1,r2,r3;
    d=(uint128_t)t0-P2_FR_P[0]; r0=(uint64_t)d; borrow=(d>>127)&1;
    d=(uint128_t)t1-P2_FR_P[1]-borrow; r1=(uint64_t)d; borrow=(d>>127)&1;
    d=(uint128_t)t2-P2_FR_P[2]-borrow; r2=(uint64_t)d; borrow=(d>>127)&1;
    d=(uint128_t)t3-P2_FR_P[3]-borrow; r3=(uint64_t)d; borrow=(d>>127)&1;
    if(!borrow){r[0]=r0;r[1]=r1;r[2]=r2;r[3]=r3;}
    else{r[0]=t0;r[1]=t1;r[2]=t2;r[3]=t3;}
}

// Modular add
static inline void p2_add(const uint64_t a[4], const uint64_t b[4], uint64_t r[4]) {
    uint128_t w; uint64_t c=0;
    w=(uint128_t)a[0]+b[0]; r[0]=(uint64_t)w; c=(uint64_t)(w>>64);
    w=(uint128_t)a[1]+b[1]+c; r[1]=(uint64_t)w; c=(uint64_t)(w>>64);
    w=(uint128_t)a[2]+b[2]+c; r[2]=(uint64_t)w; c=(uint64_t)(w>>64);
    w=(uint128_t)a[3]+b[3]+c; r[3]=(uint64_t)w; c=(uint64_t)(w>>64);
    uint64_t borrow=0; uint64_t s0,s1,s2,s3; uint128_t d;
    d=(uint128_t)r[0]-P2_FR_P[0]; s0=(uint64_t)d; borrow=(d>>127)&1;
    d=(uint128_t)r[1]-P2_FR_P[1]-borrow; s1=(uint64_t)d; borrow=(d>>127)&1;
    d=(uint128_t)r[2]-P2_FR_P[2]-borrow; s2=(uint64_t)d; borrow=(d>>127)&1;
    d=(uint128_t)r[3]-P2_FR_P[3]-borrow; s3=(uint64_t)d; borrow=(d>>127)&1;
    if(c||!borrow){r[0]=s0;r[1]=s1;r[2]=s2;r[3]=s3;}
}

// S-box: x^5
static inline void p2_sbox(uint64_t x[4]) {
    uint64_t x2[4], x4[4];
    p2_mul(x, x, x2);
    p2_mul(x2, x2, x4);
    p2_mul(x4, x, x);  // x = x^5 in-place
}

// External linear layer: M_E * [a,b,c] = [2a+b+c, a+2b+c, a+b+2c]
static inline void p2_external(uint64_t s0[4], uint64_t s1[4], uint64_t s2[4]) {
    uint64_t sum[4];
    p2_add(s0, s1, sum);
    p2_add(sum, s2, sum);
    // Now sum = a+b+c. Compute s[i] += sum (which gives 2*s[i] + others)
    p2_add(s0, sum, s0);
    p2_add(s1, sum, s1);
    p2_add(s2, sum, s2);
}

// Internal linear layer: M_I * [a,b,c] = [2a+b+c, a+2b+c, a+b+3c]
static inline void p2_internal(uint64_t s0[4], uint64_t s1[4], uint64_t s2[4]) {
    uint64_t sum[4], extra[4];
    p2_add(s0, s1, sum);
    p2_add(sum, s2, sum);
    // s0 = a + sum = 2a+b+c, s1 = b + sum = a+2b+c
    p2_add(s0, sum, s0);
    p2_add(s1, sum, s1);
    // s2 = c + sum + c = a+b+3c
    p2_add(s2, sum, extra);
    p2_add(extra, s2, s2);
}

// Poseidon2 hash: hash(a, b) = permute([a, b, 0])[0]
static void p2_hash(const uint64_t a[4], const uint64_t b[4], uint64_t out[4]) {
    uint64_t s0[4], s1[4], s2[4];
    memcpy(s0, a, 32);
    memcpy(s1, b, 32);
    memset(s2, 0, 32);

    // Initial external layer
    p2_external(s0, s1, s2);

    // First half full rounds (0..3)
    for (int r = 0; r < 4; r++) {
        p2_add(s0, P2_RC[r][0], s0);
        p2_add(s1, P2_RC[r][1], s1);
        p2_add(s2, P2_RC[r][2], s2);
        p2_sbox(s0); p2_sbox(s1); p2_sbox(s2);
        p2_external(s0, s1, s2);
    }

    // Partial rounds (4..59)
    for (int r = 4; r < 60; r++) {
        p2_add(s0, P2_RC[r][0], s0);
        p2_sbox(s0);
        p2_internal(s0, s1, s2);
    }

    // Second half full rounds (60..63)
    for (int r = 60; r < 64; r++) {
        p2_add(s0, P2_RC[r][0], s0);
        p2_add(s1, P2_RC[r][1], s1);
        p2_add(s2, P2_RC[r][2], s2);
        p2_sbox(s0); p2_sbox(s1); p2_sbox(s2);
        p2_external(s0, s1, s2);
    }

    memcpy(out, s0, 32);
}

// Thread task for parallel Merkle level building
typedef struct {
    uint64_t *tree;
    int start;
    int end;
    int levelStart;
    int parentStart;
} p2_merkle_task_t;

static void *p2_merkle_thread(void *arg) {
    p2_merkle_task_t *t = (p2_merkle_task_t *)arg;
    for (int i = t->start; i < t->end; i++) {
        p2_hash(t->tree + (t->levelStart + 2*i) * 4,
                t->tree + (t->levelStart + 2*i + 1) * 4,
                t->tree + (t->parentStart + i) * 4);
    }
    return NULL;
}

// Build Poseidon2 Merkle tree on CPU.
// Layout: tree[0..n-1] = leaves, tree[n..2n-2] = internal, tree[2n-2] = root.
// Each element is 4 x uint64_t (32 bytes, Montgomery form).
void poseidon2_merkle_tree_cpu(const uint64_t *leaves, int n, uint64_t *tree) {
    // Copy leaves
    memcpy(tree, leaves, (size_t)n * 32);

    // Build levels bottom-up
    int levelStart = 0;
    int levelSize = n;
    while (levelSize > 1) {
        int parentCount = levelSize / 2;
        int parentStart = levelStart + levelSize;

        // Multi-thread for large levels
        if (parentCount >= 256) {
            int numThreads = 4;
            if (parentCount < 1024) numThreads = 2;
            pthread_t threads[8];
            p2_merkle_task_t tasks[8];
            int chunk = parentCount / numThreads;

            for (int i = 0; i < numThreads; i++) {
                tasks[i].tree = tree;
                tasks[i].start = i * chunk;
                tasks[i].end = (i == numThreads-1) ? parentCount : (i+1)*chunk;
                tasks[i].levelStart = levelStart;
                tasks[i].parentStart = parentStart;
                pthread_create(&threads[i], NULL, p2_merkle_thread, &tasks[i]);
            }
            for (int i = 0; i < numThreads; i++) pthread_join(threads[i], NULL);
        } else {
            for (int i = 0; i < parentCount; i++) {
                p2_hash(tree + (levelStart + 2*i) * 4,
                        tree + (levelStart + 2*i + 1) * 4,
                        tree + (parentStart + i) * 4);
            }
        }

        levelStart += levelSize;
        levelSize = parentCount;
    }
}

